mapper.select:
select * from member
where provider = #{provider} and
provider_id = #{provider_id}

select count(*) from member where 1=1
and ( nickname like CONCAT( '%',#{keyword},'%' ) or email like CONCAT( '%', #{keyword}, '%' ) or ifNULL(login_id, '') like CONCAT( '%', #{keyword}, '%') or ifnull(provider, '') like CONCAT( '%', #{keyword}, '%') )
and status = #{status}
and role = #{role}

select name, member_id, login_id, nickname, email, role, status, provider, profile_img, created_date
from member
where 1=1


and (
    nickname like CONCAT( '%',#{keyword},'%' ) 
    or email like CONCAT( '%', #{keyword}, '%' )
    or ifNULL(login_id, '') like CONCAT( '%', #{keyword}, '%')
    or ifnull(provider, '') like CONCAT( '%', #{keyword}, '%')
)



and status = #{status}



and role = #{role}


order by member_id
LIMIT #{size} offset #{offset}
